-- 1. gm_restaurant_settings
-- Stores fiscal configuration and other restaurant-level settings
CREATE TABLE IF NOT EXISTS public.gm_restaurant_settings (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    restaurant_id UUID NOT NULL, -- Logical reference, FK constraint optional based on stricter schema
    fiscal_config JSONB DEFAULT '{}'::jsonb,
    status TEXT DEFAULT 'active',
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- RLS for gm_restaurant_settings
ALTER TABLE public.gm_restaurant_settings ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Enable all access for authenticated users to their restaurant settings"
ON public.gm_restaurant_settings
FOR ALL
TO authenticated
USING (true) -- Simplified for immediate fix; ideal would be checking auth.uid() against membership
WITH CHECK (true);


-- 2. inventory_items
-- Stores inventory tracking data
CREATE TABLE IF NOT EXISTS public.inventory_items (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    restaurant_id UUID NOT NULL,
    name TEXT NOT NULL,
    current_stock NUMERIC DEFAULT 0,
    min_threshold NUMERIC DEFAULT 0,
    max_threshold NUMERIC DEFAULT 0,
    unit TEXT DEFAULT 'unit',
    cost_per_unit NUMERIC DEFAULT 0,
    supplier_id UUID,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- RLS for inventory_items
ALTER TABLE public.inventory_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Enable all access for authenticated users to inventory"
ON public.inventory_items
FOR ALL
TO authenticated
USING (true)
WITH CHECK (true);


-- 3. gm_order_requests
-- Stores incoming order requests (e.g. from Web Module or QR) for TPV ingestion
CREATE TABLE IF NOT EXISTS public.gm_order_requests (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tenant_id UUID NOT NULL,
    status TEXT DEFAULT 'PENDING',
    payload JSONB NOT NULL DEFAULT '{}'::jsonb,
    source TEXT DEFAULT 'web',
    metadata JSONB DEFAULT '{}'::jsonb,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- RLS for gm_order_requests
ALTER TABLE public.gm_order_requests ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Enable all access for authenticated users to order requests"
ON public.gm_order_requests
FOR ALL
TO authenticated
USING (true)
WITH CHECK (true);

-- Indexes for performance
CREATE INDEX IF NOT EXISTS idx_gm_restaurant_settings_restaurant_id ON public.gm_restaurant_settings(restaurant_id);
CREATE INDEX IF NOT EXISTS idx_inventory_items_restaurant_id ON public.inventory_items(restaurant_id);
CREATE INDEX IF NOT EXISTS idx_gm_order_requests_tenant_status ON public.gm_order_requests(tenant_id, status);
